const body = $input.first().json.body || $input.first().json;
const invoice = body.invoice;
const tenantId = body.tenantId;

if (!invoice || !tenantId) throw new Error('Missing invoice or tenantId');

let tone, urgency;
if (invoice.days_overdue <= 14) {
  tone = 'friendly'; urgency = 'gentle reminder';
} else if (invoice.days_overdue <= 30) {
  tone = 'firm'; urgency = 'follow-up';
} else {
  tone = 'urgent'; urgency = 'final notice';
}

const amount = new Intl.NumberFormat('en-NZ', {
  style: 'currency', currency: invoice.currency || 'NZD'
}).format(invoice.amount_owed);

return [{ json: {
  invoice, tenantId, tone, urgency,
  amountFormatted: amount,
  debtorName: invoice.debtor_name,
  debtorEmail: invoice.debtor_email,
  debtorPhone: invoice.debtor_phone || null,
  invoiceNumber: invoice.invoice_number || `INV-${invoice.id.slice(0,8)}`,
  daysOverdue: invoice.days_overdue,
  dueDate: invoice.due_date,
  timesChased: invoice.times_chased
} }];

