const response = $input.first().json;
const emailBody = response.content[0].text;
const invoiceData = $('Prepare Invoice Data').first().json;

let subject;
if (invoiceData.daysOverdue <= 14) {
  subject = `Friendly reminder: ${invoiceData.invoiceNumber} — ${invoiceData.amountFormatted} outstanding`;
} else if (invoiceData.daysOverdue <= 30) {
  subject = `Payment required: ${invoiceData.invoiceNumber} — ${invoiceData.amountFormatted}`;
} else {
  subject = `URGENT: ${invoiceData.invoiceNumber} is ${invoiceData.daysOverdue} days overdue — ${invoiceData.amountFormatted}`;
}

return [{ json: { ...invoiceData, emailSubject: subject, emailBody: emailBody.trim() } }];

